Функция ОбъединитьИнтервалы(Интервалы)
    Если Интервалы = Неопределено ИЛИ Интервалы.Количество() = 0 Тогда
        Возврат Новый Массив;
    КонецЕсли;

    // Копируем интервалы, чтобы не модифицировать исходный массив
    Рабочие = Новый Массив;
    Для Каждого Интервал Из Интервалы Цикл
        Копия = Новый Массив;
        Копия.Добавить(Интервал[0]);
        Копия.Добавить(Интервал[1]);
        Рабочие.Добавить(Копия);
    КонецЦикла;

    // Сортируем по началу интервала (пузырьковая сортировка)
    Для Внешний = 0 По Рабочие.ВГраница() - 1 Цикл
        Для Внутренний = 0 По Рабочие.ВГраница() - Внешний - 1 Цикл
            Если Рабочие[Внутренний][0] > Рабочие[Внутренний + 1][0] Тогда
                Временный = Рабочие[Внутренний];
                Рабочие[Внутренний] = Рабочие[Внутренний + 1];
                Рабочие[Внутренний + 1] = Временный;
            КонецЕсли;
        КонецЦикла;
    КонецЦикла;

    // Объединяем пересекающиеся и соприкасающиеся интервалы
    Результат = Новый Массив;
    Текущий = Новый Массив;
    Текущий.Добавить(Рабочие[0][0]);
    Текущий.Добавить(Рабочие[0][1]);

    Для Сч = 1 По Рабочие.ВГраница() Цикл
        Если Рабочие[Сч][0] <= Текущий[1] Тогда
            // Пересекаются или соприкасаются — расширяем текущий интервал
            Если Рабочие[Сч][1] > Текущий[1] Тогда
                Текущий[1] = Рабочие[Сч][1];
            КонецЕсли;
        Иначе
            // Не пересекаются — сохраняем текущий и начинаем новый
            Результат.Добавить(Текущий);
            Текущий = Новый Массив;
            Текущий.Добавить(Рабочие[Сч][0]);
            Текущий.Добавить(Рабочие[Сч][1]);
        КонецЕсли;
    КонецЦикла;

    Результат.Добавить(Текущий);
    Возврат Результат;
КонецФункции

Функция СкользящееСреднее(МассивЧисел, Окно) Экспорт
    Результат = Новый Массив;
    Длина = МассивЧисел.Количество();
    Если Окно > Длина Тогда
        Возврат Результат;
    КонецЕсли;
    Для Индекс = 0 По Длина - Окно Цикл
        Сумма = 0;
        Для Сч = Индекс По Индекс + Окно - 1 Цикл
            Сумма = Сумма + МассивЧисел[Сч];
        КонецЦикла;
        Среднее = Сумма / Окно;
        Результат.Добавить(Среднее);
    КонецЦикла;
    Возврат Результат;
КонецФункции

Функция ВычислитьСкользящиеСредние(МассивЧисел, РазмерОкна) Экспорт

    // Проверка на пустой массив или некорректный размер окна
    Если МассивЧисел.Количество() = 0 Или РазмерОкна <= 0 Тогда
        Возврат Новый Массив;
    КонецЕсли;

    // Если окно больше длины массива, возвращаем пустой массив
    Если РазмерОкна > МассивЧисел.Количество() Тогда
        Возврат Новый Массив;
    КонецЕсли;

    Результат = Новый Массив;

    // Проходим по каждому возможному началу окна
    Для Индекс = 0 По МассивЧисел.Количество() - РазмерОкна Цикл

        Сумма = 0;

        // Суммируем элементы текущего окна
        Для Сч = 0 По РазмерОкна - 1 Цикл
            Сумма = Сумма + МассивЧисел[Индекс + Сч];
        КонецЦикла;

        // Вычисляем среднее и добавляем в результат
        Среднее = Сумма / РазмерОкна;
        Результат.Добавить(Среднее);

    КонецЦикла;

    Возврат Результат;

КонецФункции

Функция СкользящиеСредние(МассивЧисел, Окно)

