Функция СкользящееСреднее(МассивЧисел, Окно)
	Результат = Новый Массив;
	Количество = МассивЧисел.Количество();

	Если Количество < Окно ИЛИ Окно < 1 Тогда
		Возврат Результат;
	КонецЕсли;

	Сумма = 0;
	Для К = 0 По Окно - 1 Цикл
		Сумма = Сумма + МассивЧисел[К];
	КонецЦикла;
	Результат.Добавить(Сумма / Окно);

	Для С = 1 По Количество - Окно Цикл
		Сумма = Сумма - МассивЧисел[С - 1] + МассивЧисел[С + Окно - 1];
		Результат.Добавить(Сумма / Окно);
	КонецЦикла;

	Возврат Результат;
