Функция ПодсчитатьСлова(Текст) Экспорт
    Текст = НРег(Текст);
    Разделители = " .,!?:;()[]{}'""-—" + Символы.ПС + Символы.ВК + Символы.Таб;
    МассивСлов = СтрРазделить(Текст, Разделители, Ложь);
    Результат = Новый Структура;
    Для Каждого Слово Из МассивСлов Цикл
        Если Результат.Свойство(Слово) Тогда
            Результат[Слово] = Результат[Слово] + 1;
        Иначе
            Результат.Вставить(Слово, 1);
        КонецЕсли;
    КонецЦикла;
    Возврат Результат;
КонецФункции

Функция ПосчитатьСлова(Текст)
    Результат = Новый Структура;
    ТекущееСлово = "";
    Для i = 1 По СтрДлина(Текст) Цикл
        Символ = Сред(Текст, i, 1);
        Если ЯвляетсяЧастьюСлова(Символ) Тогда
            ТекущееСлово = ТекущееСлово + Символ;
        Иначе
            Если ТекущееСлово <> "" Тогда
                СловоНиж = НРег(ТекущееСлово);
                Если Результат.Свойство(СловоНиж) Тогда
                    Результат[СловоНиж] = Результат[СловоНиж] + 1;
                Иначе
                    Результат.Вставить(СловоНиж, 1);
                КонецЕсли;
                ТекущееСлово = "";
            КонецЕсли;
        КонецЕсли;
    КонецЦикла;
    Если ТекущееСлово <> "" Тогда
        СловоНиж = НРег(ТекущееСлово);
        Если Результат.Свойство(СловоНиж) Тогда
            Результат[СловоНиж] = Результат[СловоНиж] + 1;
        Иначе
            Результат.Вставить(СловоНиж, 1);
        КонецЕсли;
    КонецЕсли;
    Возврат Результат;
КонецФункции

