Функция ПодсчитатьСлова(Текст) Экспорт
    Результат = Новый Структура;
    Разделители = " " + Символы.Таб + Символы.ПС + Символы.ВК + Символы.НПП + ".,!?;:""()[]{}<>/\-_=+|@#$%^&*~`«»—";
    ТекущееСлово = "";

    Для Индекс = 1 По СтрДлина(Текст) Цикл
        Символ = Сред(Текст, Индекс, 1);
        Если СтрНайти(Разделители, Символ) > 0 Тогда
            Если Не ПустаяСтрока(ТекущееСлово) Тогда
                Слово = НРег(ТекущееСлово);
                Если Результат.Свойство(Слово) Тогда
                    Результат[Слово] = Результат[Слово] + 1;
                Иначе
                    Результат.Вставить(Слово, 1);
                КонецЕсли;
                ТекущееСлово = "";
            КонецЕсли;
        Иначе
            ТекущееСлово = ТекущееСлово + Символ;
        КонецЕсли;
    КонецЦикла;

    Если Не ПустаяСтрока(ТекущееСлово) Тогда
        Слово = НРег(ТекущееСлово);
        Если Результат.Свойство(Слово) Тогда
            Результат[Слово] = Результат[Слово] + 1;
        Иначе
            Результат.Вставить(Слово, 1);
        КонецЕсли;
    КонецЕсли;

    Возврат Результат;
КонецФункции

Функция ПодсчитатьСлова(Текст) Экспорт

	Статистика = Новый Структура;

	Если ПустаяСтрока(Текст) Тогда
		Возврат Статистика;
	КонецЕсли;

	ТекстНРег = НРег(Текст);

	ЗнакиПрепинания = ".,;:!?""'()[]{}<>«»„“”‘’-–—…/\|@#$%^&*+=~`"
		+ Символы.Таб + Символы.ВК + Символы.ПС
		+ Символы.ВТаб + Символы.ПФ + Символы.НПП;

	Для Индекс = 1 По СтрДлина(ЗнакиПрепинания) Цикл
		ТекстНРег = СтрЗаменить(ТекстНРег, Сред(ЗнакиПрепинания, Индекс, 1), " ");
	КонецЦикла;

	МассивСлов = СтрРазделить(ТекстНРег, " ", Ложь);

	Для Каждого Слово Из МассивСлов Цикл

		Если Статистика.Свойство(Слово) Тогда
			Статистика[Слово] = Статистика[Слово] + 1;
		Иначе
			Статистика.Вставить(Слово, 1);
		КонецЕсли;

	КонецЦикла;

	Возврат Статистика;

КонецФункции

Функция ПодсчетСлов(Текст) Экспорт
    Результат = Новый Структура;
    НижнийТекст = Нрег(Текст);

    // Удаляем знаки препинания, оставляем только буквы, цифры и пробелы
    СимволыДляУдаления = ",.;:!?()[]{}""''—–-«»/\\|@#$%^&*+=<>~`";
    Для Индекс = 1 По СтрДлина(СимволыДляУдаления) Цикл
        Символ = Сред(СимволыДляУдаления, Индекс, 1);
        НижнийТекст = СтрЗаменить(НижнийТекст, Символ, " ");
    КонецЦикла;

    // Разбиваем текст на слова по пробелам
    МассивСлов = СтрРазделить(НижнийТекст, " ");

    Для Каждого Слово Из МассивСлов Цикл
        Слово = СокрЛП(Слово);
        Если ЗначениеЗаполнено(Слово) Тогда
            Если Результат.Свойство(Слово) Тогда
                Результат[Слово] = Результат[Слово] + 1;
            Иначе
                Результат.Вставить(Слово, 1);
            КонецЕсли;
        КонецЕсли;
    КонецЦикла;

    Возврат Результат;
КонецФункции

Функция ПодсчитатьСлова(Знач Текст) Экспорт

    Результат = Новый Структура;

    // Заменяем знаки препинания на пробелы
    ЗнакиПунктуации = ",.:;!?-–—()[]{}»«""''""/\@#$%^&*+=<>|~`";
    РабочийТекст = НРег(Текст);

    Для Индекс = 1 По СтрДлина(ЗнакиПунктуации) Цикл
        Символ = Сред(ЗнакиПунктуации, Индекс, 1);
        РабочийТекст = СтрЗаменить(РабочийТекст, Символ, " ");
    КонецЦикла;

    // Разбиваем на слова по пробелам
    МассивСлов = СтрРазделить(РабочийТекст, " ", Ложь);

    // Подсчитываем вхождения
    Для Каждого Слово Из МассивСлов Цикл

        // Убираем оставшиеся пробелы по краям (на всякий случай)
        Слово = СокрЛП(Слово);
        Если Слово = "" Тогда
            Продолжить;
        КонецЕсли;

        Если Результат.Свойство(Слово) Тогда
            Результат[Слово] = Результат[Слово] + 1;
        Иначе
            Результат.Вставить(Слово, 1);
        КонецЕсли;

    КонецЦикла;

    Возврат Результат;

КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)
    Длина1 = СтрДлина(Строка1);
    Длина2 = СтрДлина(Строка2);
    Матрица = Новый Массив(Длина1 + 1, Длина2 + 1);
    Для i = 0 По Длина1 Цикл
        Матрица[i][0] = i;
    КонецЦикла;
    Для j = 0 По Длина2 Цикл
        Матрица[0][j] = j;
    КонецЦикла;
    Для i = 1 По Длина1 Цикл
        Для j = 1 По Длина2 Цикл
            Симв1 = Сред(Строка1, i, 1);
            Симв2 = Сред(Строка2, j, 1);
            Если Симв1 = Симв2 Тогда
                Замена = 0;
            Иначе
                Замена = 1;
            КонецЕсли;
            Удалить = Матрица[i - 1][j] + 1;
            Вставить = Матрица[i][j - 1] + 1;
            Заменить = Матрица[i - 1][j - 1] + Замена;
            Матрица[i][j] = Мин(Удалить, Вставить, Заменить);
        КонецЦикла;
    КонецЦикла;
    Возврат Матрица[Длина1][Длина2];
КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2) Экспорт
    Длина1 = СтрДлина(Строка1);
    Длина2 = СтрДлина(Строка2);
    Если Длина1 = 0 Тогда
        Возврат Длина2;
    КонецЕсли;
    Если Длина2 = 0 Тогда
        Возврат Длина1;
    КонецЕсли;

    Матрица = Новый Массив(Длина1 + 1);
    Для i = 0 По Длина1 Цикл
        Матрица[i] = Новый Массив(Длина2 + 1);
    КонецЦикла;

    Для i = 0 По Длина1 Цикл
        Матрица[i][0] = i;
    КонецЦикла;
    Для j = 0 По Длина2 Цикл
        Матрица[0][j] = j;
    КонецЦикла;

    Для i = 1 По Длина1 Цикл
        Символ1 = Сред(Строка1, i, 1);
        Для j = 1 По Длина2 Цикл
            Символ2 = Сред(Строка2, j, 1);
            Стоимость = ?(Символ1 = Символ2, 0, 1);
            Матрица[i][j] = Мин(Матрица[i-1][j] + 1, Матрица[i][j-1] + 1, Матрица[i-1][j-1] + Стоимость);
        КонецЦикла;
    КонецЦикла;

    Возврат Матрица[Длина1][Длина2];
КонецФункции

Функция Левенштейн(Стр1, Стр2)

    // Оптимизация: меняем строки местами, чтобы меньшая строка была по вертикали (по столбцам)
    // Это уменьшает потребление памяти.
    Если СтрДлина(Стр1) < СтрДлина(Стр2) Тогда
        Возврат Левенштейн(Стр2, Стр1);
    КонецЕсли;

    // Инициализация предыдущей строки (расстояние от пустой строки к префиксам Стр2)
    // D[0][j] = j
    ПредыдущаяСтрока = Новый Массив;
    Для к = 0 По СтрДлина(Стр2) Цикл
        ПредыдущаяСтрока.Добавить(к);
    КонецЦикла;

    // Перебор символов первой строки
    Для i = 1 По СтрДлина(Стр1) Цикл
        // Инициализация текущей строки
        // D[i][0] = i
        ТекущаяСтрока = Новый Массив;
        ТекущаяСтрока.Добавить(i);

        Для j = 1 По СтрДлина(Стр2) Цикл
            // Стоимость замены: 0, если символы совпадают, иначе 1
            Если Сред(Стр1, i, 1) = Сред(Стр2, j, 1) Тогда
                Стоимость = 0;
            Иначе
                Стоимость = 1;
            КонецЕсли;

            // Вычисление минимума из трех операций:
            // 1. Удаление (ПредыдущаяСтрока[j] + 1)
            // 2. Вставка (ТекущаяСтрока[j-1] + 1)
            // 3. Замена (ПредыдущаяСтрока[j-1] + Стоимость)
            ТекущаяСтрока.Добавить(Мин(
                ПредыдущаяСтрока[j] + 1,
                ТекущаяСтрока[j-1] + 1,
                ПредыдущаяСтрока[j-1] + Стоимость
            ));
        КонецЦикла;

        // Переход к следующей итерации
        ПредыдущаяСтрока = ТекущаяСтрока;
    КонецЦикла;

    // Результат находится в последней ячейке матрицы
    Возврат ПредыдущаяСтрока[СтрДлина(Стр2)];

КонецФункции

Функция Левенштейн(Строка1, Строка2) Экспорт

	М = СтрДлина(Строка1);
	Н = СтрДлина(Строка2);

	Если М = 0 Тогда
		Возврат Н;
	КонецЕсли;

	Если Н = 0 Тогда
		Возврат М;
	КонецЕсли;

	Матрица = Новый Массив;
	Для Инд1 = 0 По М Цикл
		СтрокаМатрицы = Новый Массив;
		Для Инд2 = 0 По Н Цикл
			Если Инд1 = 0 Тогда
				СтрокаМатрицы.Добавить(Инд2);
			ИначеЕсли Инд2 = 0 Тогда
				СтрокаМатрицы.Добавить(Инд1);
			Иначе
				СтрокаМатрицы.Добавить(0);
			КонецЕсли;
		КонецЦикла;
		Матрица.Добавить(СтрокаМатрицы);
	КонецЦикла;

	Для Инд1 = 1 По М Цикл
		Для Инд2 = 1 По Н Цикл
			Символ1 = Сред(Строка1, Инд1, 1);
			Символ2 = Сред(Строка2, Инд2, 1);

			Стоимость = ?(Символ1 = Символ2, 0, 1);

			Удаление = Матрица[Инд1 - 1][Инд2] + 1;
			Вставка = Матрица[Инд1][Инд2 - 1] + 1;
			Замена = Матрица[Инд1 - 1][Инд2 - 1] + Стоимость;

			Матрица[Инд1][Инд2] = Мин(Мин(Удаление, Вставка), Замена);
		КонецЦикла;
	КонецЦикла;

	Возврат Матрица[М][Н];

КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)
    n = СтрДлина(Строка1);
    m = СтрДлина(Строка2);

    Если n = 0 Тогда
        Возврат m;
    КонецЕсли;
    Если m = 0 Тогда
        Возврат n;
    КонецЕсли;

    Предыдущий = Новый Массив;
    Текущий = Новый Массив;

    // инициализация первой строки таблицы
    Для j = 0 По m Цикл
        Предыдущий.Добавить(j);
    КонецЦикла;

    Для i = 1 По n Цикл
        Текущий.Очистить();
        Текущий.Добавить(i); // первая колонка текущей строки

        Для j = 1 По m Цикл
            Если Сред(Строка1, i, 1) = Сред(Строка2, j, 1) Тогда
                cost = 0;
            Иначе
                cost = 1;
            КонецЕсли;

            del = Предыдущий[j] + 1;
            ins = Текущий[j - 1] + 1;
            sub = Предыдущий[j - 1] + cost;

            min = del;
            Если ins < min Тогда min = ins; КонецЕсли;
            Если sub < min Тогда min = sub; КонецЕсли;

            Текущий.Добавить(min);
        КонецЦикла;

        // меняем ссылки массивов
        Временный = Предыдущий;
        Предыдущий = Текущий;
        Текущий = Временный;
    КонецЦикла;

    Возврат Предыдущий[m];
КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)
    Длина1 = СтрДлина(Строка1);
    Длина2 = СтрДлина(Строка2);

    Если Длина1 = 0 Тогда
        Возврат Длина2;
    КонецЕсли;

    Если Длина2 = 0 Тогда
        Возврат Длина1;
    КонецЕсли;

    Предыдущая = Новый Массив(Длина2 + 1);
    Текущая    = Новый Массив(Длина2 + 1);

    Для j = 0 По Длина2 Цикл
        Предыдущая[j] = j;
    КонецЦикла;

    Для i = 1 По Длина1 Цикл
        Текущая[0] = i;
        Символ1 = Сред(Строка1, i, 1);

        Для j = 1 По Длина2 Цикл
            Символ2 = Сред(Строка2, j, 1);
            СтоимостьЗамены = ?(Символ1 = Символ2, 0, 1);

            Удаление = Предыдущая[j] + 1;
            Вставка  = Текущая[j - 1] + 1;
            Замена   = Предыдущая[j - 1] + СтоимостьЗамены;

            Текущая[j] = Мин(Удаление, Мин(Вставка, Замена));
        КонецЦикла;

        Временная = Предыдущая;
        Предыдущая = Текущая;
        Текущая = Временная;
    КонецЦикла;

    Возврат Предыдущая[Длина2];
КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2) Экспорт

	Длина1 = СтрДлина(Строка1);
	Длина2 = СтрДлина(Строка2);

	Если Длина1 = 0 Тогда
		Возврат Длина2;
	КонецЕсли;

	Если Длина2 = 0 Тогда
		Возврат Длина1;
	КонецЕсли;

	ПредыдущаяСтрока = Новый Массив(Длина2 + 1);
	ТекущаяСтрока = Новый Массив(Длина2 + 1);

	Для Индекс = 0 По Длина2 Цикл
		ПредыдущаяСтрока[Индекс] = Индекс;
	КонецЦикла;

	Для Индекс1 = 1 По Длина1 Цикл

		ТекущаяСтрока[0] = Индекс1;
		Символ1 = Сред(Строка1, Индекс1, 1);

		Для Индекс2 = 1 По Длина2 Цикл

			Символ2 = Сред(Строка2, Индекс2, 1);

			Если Символ1 = Символ2 Тогда
				Стоимость = 0;
			Иначе
				Стоимость = 1;
			КонецЕсли;

			Удаление = ПредыдущаяСтрока[Индекс2] + 1;
			Вставка = ТекущаяСтрока[Индекс2 - 1] + 1;
			Замена = ПредыдущаяСтрока[Индекс2 - 1] + Стоимость;

			ТекущаяСтрока[Индекс2] = Мин(Мин(Удаление, Вставка), Замена);

		КонецЦикла;

		ВременнаяСтрока = ПредыдущаяСтрока;
		ПредыдущаяСтрока = ТекущаяСтрока;
		ТекущаяСтрока = ВременнаяСтрока;

	КонецЦикла;

	Возврат ПредыдущаяСтрока[Длина2];

КонецФункции

Функция РедакционноеРасстояние(Строка1, Строка2) Экспорт
    ДлинаСтроки1 = СтрДлина(Строка1);
    ДлинаСтроки2 = СтрДлина(Строка2);

    // Создаем двумерный массив (матрицу)
    Матрица = Новый Массив(ДлинаСтроки1 + 1);
    Для i = 0 По ДлинаСтроки1 Цикл
        Матрица[i] = Новый Массив(ДлинаСтроки2 + 1);
        Для j = 0 По ДлинаСтроки2 Цикл
            Матрица[i][j] = 0;
        КонецЦикла;
    КонецЦикла;

    // Инициализация первой строки и первого столбца
    Для i = 0 По ДлинаСтроки1 Цикл
        Матрица[i][0] = i;
    КонецЦикла;
    Для j = 0 По ДлинаСтроки2 Цикл
        Матрица[0][j] = j;
    КонецЦикла;

    // Заполнение матрицы
    Для i = 1 По ДлинаСтроки1 Цикл
        Для j = 1 По ДлинаСтроки2 Цикл
            Стоимость = ?(Сред(Строка1, i, 1) = Сред(Строка2, j, 1), 0, 1);

            Матрица[i][j] = Мин(
                Матрица[i - 1][j] + 1,       // удаление
                Матрица[i][j - 1] + 1,       // вставка
                Матрица[i - 1][j - 1] + Стоимость  // замена
            );
        КонецЦикла;
    КонецЦикла;

    Возврат Матрица[ДлинаСтроки1][ДлинаСтроки2];
КонецФункции

Функция РасстояниеЛевенштейна(Строка1, Строка2)

    ДлинаСтроки1 = СтрДлина(Строка1);
    ДлинаСтроки2 = СтрДлина(Строка2);

    // Создание матрицы (ДлинаСтроки1+1) x (ДлинаСтроки2+1)
    Матрица = Новый Массив(ДлинаСтроки1 + 1);
    Для Индекс1 = 0 По ДлинаСтроки1 Цикл
        Матрица[Индекс1] = Новый Массив(ДлинаСтроки2 + 1);
        Матрица[Индекс1][0] = Индекс1;
    КонецЦикла;
    Для Индекс2 = 0 По ДлинаСтроки2 Цикл
        Матрица[0][Индекс2] = Индекс2;
    КонецЦикла;

    // Заполнение матрицы
    Для Индекс1 = 1 По ДлинаСтроки1 Цикл
        Символ1 = Сред(Строка1, Индекс1, 1);
        Для Индекс2 = 1 По ДлинаСтроки2 Цикл
            Символ2 = Сред(Строка2, Индекс2, 1);
            Если Символ1 = Символ2 Тогда
                Стоимость = 0;
            Иначе
                Стоимость = 1;
            КонецЕсли;

            Матрица[Индекс1][Индекс2] = Мин(
                Матрица[Индекс1 - 1][Индекс2] + 1,       // удаление
                Матрица[Индекс1][Индекс2 - 1] + 1,       // вставка
                Матрица[Индекс1 - 1][Индекс2 - 1] + Стоимость // замена или совпадение
            );
        КонецЦикла;
    КонецЦикла;

    Возврат Матрица[ДлинаСтроки1][ДлинаСтроки2];

