Функция РасстояниеЛевенштейна(Строка1, Строка2)

    Длина1 = СтрДлина(Строка1);
    Длина2 = СтрДлина(Строка2);

    Если Длина1 = 0 Тогда
        Возврат Длина2;
    КонецЕсли;

    Если Длина2 = 0 Тогда
        Возврат Длина1;
    КонецЕсли;

    М = Новый Массив(Длина1 + 1, Длина2 + 1);

    Для Индекс1 = 0 По Длина1 Цикл
        М[Индекс1][0] = Индекс1;
    КонецЦикла;

    Для Индекс2 = 0 По Длина2 Цикл
        М[0][Индекс2] = Индекс2;
    КонецЦикла;

    Для Индекс1 = 1 По Длина1 Цикл
        Для Индекс2 = 1 По Длина2 Цикл
            Символ1 = Сред(Строка1, Индекс1, 1);
            Символ2 = Сред(Строка2, Индекс2, 1);

            Если Символ1 = Символ2 Тогда
                СтоимостьЗамены = 0;
            Иначе
                СтоимостьЗамены = 1;
            КонецЕсли;

            Удаление = М[Индекс1 - 1][Индекс2] + 1;
            Вставка = М[Индекс1][Индекс2 - 1] + 1;
            Замена = М[Индекс1 - 1][Индекс2 - 1] + СтоимостьЗамены;

            М[Индекс1][Индекс2] = Мин(Мин(Удаление, Вставка), Замена);
        КонецЦикла;
    КонецЦикла;

    Возврат М[Длина1][Длина2];

