Функция СтрокиАнаграммы(Строка1, Строка2)

	С1 = СтрЗаменить(НРег(Строка1), " ", "");
	С2 = СтрЗаменить(НРег(Строка2), " ", "");

	Если СтрДлина(С1) <> СтрДлина(С2) Тогда
		Возврат Ложь;
	КонецЕсли;

	Карта = Новый Соответствие;

	Для Индекс = 1 По СтрДлина(С1) Цикл
		Символ = Сред(С1, Индекс, 1);
		Карта[Символ] = ?(Карта[Символ] = Неопределено, 1, Карта[Символ] + 1);
	КонецЦикла;

	Для Индекс = 1 По СтрДлина(С2) Цикл
		Символ = Сред(С2, Индекс, 1);
		Если Карта[Символ] = Неопределено Тогда
			Возврат Ложь;
		КонецЕсли;
		Карта[Символ] = Карта[Символ] - 1;
		Если Карта[Символ] = 0 Тогда
			Карта.Удалить(Символ);
		КонецЕсли;
	КонецЦикла;

	Возврат Карта.Количество() = 0;

КонецФункции

Функция ЭтоАнаграмма(Строка1, Строка2) Экспорт

	Строка1 = НРег(СтрЗаменить(Строка1, " ", ""));
	Строка2 = НРег(СтрЗаменить(Строка2, " ", ""));

	Если СтрДлина(Строка1) <> СтрДлина(Строка2) Тогда
		Возврат Ложь;
	КонецЕсли;

	КоличествоСимволов = Новый Соответствие;

	Для Индекс = 1 По СтрДлина(Строка1) Цикл
		Символ = Сред(Строка1, Индекс, 1);
		ТекущееКоличество = КоличествоСимволов[Символ];
		КоличествоСимволов[Символ] = ?(ТекущееКоличество = Неопределено, 1, ТекущееКоличество + 1);
	КонецЦикла;

	Для Индекс = 1 По СтрДлина(Строка2) Цикл
		Символ = Сред(Строка2, Индекс, 1);
		ТекущееКоличество = КоличествоСимволов[Символ];
		Если ТекущееКоличество = Неопределено Тогда
			Возврат Ложь;
		КонецЕсли;
		Если ТекущееКоличество = 1 Тогда
			КоличествоСимволов.Удалить(Символ);
		Иначе
			КоличествоСимволов[Символ] = ТекущееКоличество - 1;
		КонецЕсли;
	КонецЦикла;

	Возврат КоличествоСимволов.Количество() = 0;

КонецФункции

