    С2 = ВРег(СокрЛП(Строка2));
    С2 = СтрЗаменить(С2, " ", "");

    Если СтрДлина(С1) <> СтрДлина(С2) Тогда
        Возврат Ложь;
    КонецЕсли;

    Для Инд = 1 По СтрДлина(С1) Цикл
        Символ = Сред(С1, Инд, 1);
        Позиция = Найти(С2, Символ);
        Если Позиция = 0 Тогда
            Возврат Ложь;
        КонецЕсли;
        С2 = Лев(С2, Позиция - 1) + Сред(С2, Позиция + 1);
    КонецЦикла;

    Возврат Истина;

