Функция ПростыеЧисла(Граница)
    Если Граница < 2 Тогда
        Возврат Новый Массив;
    КонецЕсли;
    Массив = Новый Массив;
    Для Индекс = 0 По Граница Цикл
        Массив.Добавить(Истина);
    КонецЦикла;
    Массив[0] = Ложь;
    Массив[1] = Ложь;
    Для i = 2 По Цел(Sqrt(Граница)) Цикл
        Если Массив[i] Тогда
            j = i * i;
            Пока j <= Граница Цикл
                Массив[j] = Ложь;
                j = j + i;
            КонецЦикла;
        КонецЕсли;
    КонецЦикла;
    Результат = Новый Массив;
    Для i = 2 По Граница Цикл
        Если Массив[i] Тогда
            Результат.Добавить(i);
        КонецЕсли;
    КонецЦикла;
    Возврат Результат;
КонецФункции

