Функция ПростыеЧисла(Граница) Экспорт

	Результат = Новый Массив;

	Если Граница < 2 Тогда
		Возврат Результат;
	КонецЕсли;

	Решето = Новый Массив(Граница + 1);
	Для Индекс = 0 По Граница Цикл
		Решето[Индекс] = Истина;
	КонецЦикла;
	Решето[0] = Ложь;
	Решето[1] = Ложь;

	Делитель = 2;
	Пока Делитель * Делитель <= Граница Цикл
		Если Решето[Делитель] Тогда
			Кратное = Делитель * Делитель;
			Пока Кратное <= Граница Цикл
				Решето[Кратное] = Ложь;
				Кратное = Кратное + Делитель;
			КонецЦикла;
		КонецЕсли;
		Делитель = Делитель + 1;
	КонецЦикла;

	Для Индекс = 2 По Граница Цикл
		Если Решето[Индекс] Тогда
			Результат.Добавить(Индекс);
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;

