Функция ОбъединитьИОтсортироватьМассивы(Знач ИсходныйМассив, Знач НовыеЗначения)

	// Создаём результирующий массив и копируем все элементы из обоих массивов
	Результат = Новый Массив;

	Для Каждого Элемент Из ИсходныйМассив Цикл
		Результат.Добавить(Элемент);
	КонецЦикла;

	Для Каждого Элемент Из НовыеЗначения Цикл
		Результат.Добавить(Элемент);
	КонецЦикла;

	// Если массив пуст или из одного элемента — сортировка не нужна
	Если Результат.Количество() <= 1 Тогда
		Возврат Результат;
	КонецЕсли;

	// Сортировка через ТаблицуЗначений
	ТаблицаСортировки = Новый ТаблицаЗначений;
	ТаблицаСортировки.Колонки.Добавить("Значение");
	ТаблицаСортировки.Колонки.Добавить("Порядок", Новый ОписаниеТипов("Число"));

	ПорядковыйНомер = 0;
	Для Каждого Элемент Из Результат Цикл
		СтрокаТЗ = ТаблицаСортировки.Добавить();
		СтрокаТЗ.Значение = Элемент;
		СтрокаТЗ.Порядок = ПорядковыйНомер;
		ПорядковыйНомер = ПорядковыйНомер + 1;
	КонецЦикла;

	ТаблицаСортировки.Сортировать("Значение, Порядок");

	Результат = Новый Массив;
	Для Каждого СтрокаТЗ Из ТаблицаСортировки Цикл
		Результат.Добавить(СтрокаТЗ.Значение);
	КонецЦикла;

	Возврат Результат;

