// Функция возвращает количество рабочих дней в периоде.
//
// Параметры:
//  ДатаНачала - Дата - начало периода (включительно)
//  ДатаКонца  - Дата - конец периода (включительно)
//  Праздники  - Массив - массив дат-праздников
//
// Возвращаемое значение:
//  Число - количество рабочих дней
Функция КоличествоРабочихДней(ДатаНачала, ДатаКонца, Праздники) Экспорт

	Если ДатаКонца < ДатаНачала Тогда
		Возврат 0;
	КонецЕсли;

	// Приводим даты к началу дня
	ДатаНачала = НачалоДня(ДатаНачала);
	ДатаКонца = НачалоДня(ДатаКонца);

	// Индексируем праздники для быстрого поиска
	ПраздникиКлюч = Новый Соответствие;
	Для Каждого Праздник Из Праздники Цикл
		Если ТипЗнч(Праздник) = Тип("Дата") Тогда
			ПраздникиКлюч.Вставить(НачалоДня(Праздник), Истина);
		КонецЕсли;
	КонецЦикла;

	Результат = 0;
	ТекущаяДата = ДатаНачала;

	Пока ТекущаяДата <= ДатаКонца Цикл

		ДеньНедели = ДеньНедели(ТекущаяДата); // 1 = понедельник, ..., 7 = воскресенье

		Если ДеньНедели >= 1 И ДеньНедели <= 5 Тогда
			// Будний день
			ЭтоПраздник = ПраздникиКлюч.Получить(ТекущаяДата) <> Неопределено;

			Если Не ЭтоПраздник Тогда
				Результат = Результат + 1;
			КонецЕсли;
		КонецЕсли;

		ТекущаяДата = ТекущаяДата + 60 * 60 * 24; // +1 день

	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция КоличествоРабочихДней(ДатаНачала, ДатаОкончания, МассивПраздников) Экспорт

