        Праздники.Вставить(НачалоДня(Праздник), Истина);
    КонецЦикла;

    Результат = 0;
    ТекДата   = Начало;

    Пока ТекДата <= Конец Цикл
        ДеньНеделиЧисло = ДеньНедели(ТекДата);
        Если ДеньНеделиЧисло >= 1 И ДеньНеделиЧисло <= 5 Тогда
            Если Праздники.Получить(ТекДата) = Неопределено Тогда
                Результат = Результат + 1;
            КонецЕсли;
        КонецЕсли;
        ТекДата = ТекДата + 86400;
    КонецЦикла;

    Возврат Результат;

