Функция ЧислоРабочихДней(НачалоПериода, КонецПериода, МассивПраздников) Экспорт

	Если КонецПериода < НачалоПериода Тогда
		Возврат 0;
	КонецЕсли;

	// Праздники приводим к началу дня и помещаем в соответствие для быстрого поиска
	Праздники = Новый Соответствие;
	Для Каждого ДатаПраздника Из МассивПраздников Цикл
		Праздники.Вставить(НачалоДня(ДатаПраздника), Истина);
	КонецЦикла;

	РабочихДней = 0;
	ТекущаяДата = НачалоДня(НачалоПериода);
	ПоследнийДень = НачалоДня(КонецПериода);

	Пока ТекущаяДата <= ПоследнийДень Цикл
		ДеньНеделиТекущий = ДеньНедели(ТекущаяДата); // 1 - понедельник, 7 - воскресенье
		Если ДеньНеделиТекущий <= 5 Тогда
			Если Праздники[ТекущаяДата] = Неопределено Тогда
				РабочихДней = РабочихДней + 1;
			КонецЕсли;
		КонецЕсли;
		ТекущаяДата = ТекущаяДата + 86400; // шаг в одни сутки
	КонецЦикла;

	Возврат РабочихДней;

