Функция ПеревернутьСлова(Строка) Экспорт

	МассивСлов = СтрРазделить(Строка, " ", Ложь);
	МассивРезультат = Новый Массив;

	Для Индекс = 0 По МассивСлов.Количество() - 1 Цикл
		МассивРезультат.Добавить(МассивСлов[МассивСлов.Количество() - 1 - Индекс]);
	КонецЦикла;

	Возврат СтрСоединить(МассивРезультат, " ");

КонецФункции

Функция ПеревернутьПорядокСлов(Знач ИсходнаяСтрока)

	Результат = "";

	// Убираем лишние пробелы по краям
	ИсходнаяСтрока = СокрЛП(ИсходнаяСтрока);

	// Заменяем множественные пробелы на одинарные
	Пока Найти(ИсходнаяСтрока, "  ") > 0 Цикл
		ИсходнаяСтрока = СтрЗаменить(ИсходнаяСтрока, "  ", " ");
	КонецЦикла;

	// Если строка пустая — возвращаем пустую строку
	Если ИсходнаяСтрока = "" Тогда
		Возврат "";
	КонецЕсли;

	// Разбиваем строку на массив слов
	МассивСлов = Новый Массив;
	Остаток = ИсходнаяСтрока;

	Пока Остаток <> "" Цикл
		ПозицияПробела = Найти(Остаток, " ");
		Если ПозицияПробела > 0 Тогда
			МассивСлов.Добавить(Лев(Остаток, ПозицияПробела - 1));
			Остаток = Сред(Остаток, ПозицияПробела + 1);
		Иначе
			МассивСлов.Добавить(Остаток);
			Остаток = "";
		КонецЕсли;
	КонецЦикла;

	// Собираем массив в обратном порядке
	Для Индекс = -МассивСлов.Количество() + 1 По 0 Цикл
		Если Результат <> "" Тогда
			Результат = Результат + " ";
		КонецЕсли;
		Результат = Результат + МассивСлов[-Индекс];
	КонецЦикла;

	Возврат Результат;

КонецФункции

Функция РазвернутьСлова(Знач ИсходнаяСтрока)
    Строка = СокрЛП(ИсходнаяСтрока);
    Если ПустаяСтрока(Строка) Тогда
        Возврат "";
    КонецЕсли;

    Пока Найти(Строка, "  ") > 0 Цикл
        Строка = СтрЗаменить(Строка, "  ", " ");
    КонецЦикла;

    МассивСлов = СтрРазделить(Строка, " ", Ложь);

    Левый  = 0;
    Правый = МассивСлов.ВГраница();
    Пока Левый < Правый Цикл
        Временное       = МассивСлов[Левый];
        МассивСлов[Левый]  = МассивСлов[Правый];
        МассивСлов[Правый] = Временное;
        Левый  = Левый  + 1;
        Правый = Правый - 1;
    КонецЦикла;

    Возврат СтрСоединить(МассивСлов, " ");
КонецФункции

Функция СтепеньПоМодулю(Основание, Показатель, Модуль)
    Если Модуль = 1 Тогда
        Возврат 0;
    КонецЕсли;

    Если Показатель = 0 Тогда
        Возврат 1;
    КонецЕсли;

    Результат = 1;
    Основание = Основание % Модуль;

    Пока Показатель > 0 Цикл
        Если Показатель % 2 = 1 Тогда
            Результат = (Результат * Основание) % Модуль;
        КонецЕсли;
        Основание = (Основание * Основание) % Модуль;
        Показатель = Цел(Показатель / 2);
    КонецЦикла;

    Возврат Результат;
