Функция ПолучитьОстаткиТоваровНаСкладе(МассивНоменклатуры, Склад, ГруппаНоменклатуры = Неопределено) Экспорт

    ТаблицаОстатков = Новый ТаблицаЗначений;
    ТаблицаОстатков.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    ТаблицаОстатков.Колонки.Добавить("Остаток", Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 3)));

    Если МассивНоменклатуры.Количество() > 0 Тогда
        Запрос = Новый Запрос;
        Запрос.Текст = "
        |ВЫБРАТЬ
        |    ТоварыНаСкладахОстатки.Номенклатура КАК Номенклатура,
        |    ТоварыНаСкладахОстатки.ВНаличииОстаток КАК Остаток
        |ИЗ
        |    РегистрНакопления.ТоварыНаСкладах.Остатки КАК ТоварыНаСкладахОстатки
        |ГДЕ
        |    ТоварыНаСкладахОстатки.Склад = &Склад
        |    И ТоварыНаСкладахОстатки.Номенклатура В (&МассивНоменклатуры)
        |";
        Запрос.УстановитьПараметр("Склад", Склад);
        Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
        РезультатЗапроса = Запрос.Выполнить();
        Выборка = РезультатЗапроса.Выбрать();
        Пока Выборка.Следующий() Цикл
            НоваяСтрока = ТаблицаОстатков.Добавить();
            НоваяСтрока.Номенклатура = Выборка.Номенклатура;
            НоваяСтрока.Остаток = Выборка.Остаток;
        КонецЦикла;
    ИначеЕсли ГруппаНоменклатуры <> Неопределено Тогда
        Запрос = Новый Запрос;
        Запрос.Текст = "
        |ВЫБРАТЬ
        |    ТоварыНаСкладахОстатки.Номенклатура КАК Номенклатура,
        |    ТоварыНаСкладахОстатки.ВНаличииОстаток КАК Остаток
        |ИЗ
        |    РегистрНакопления.ТоварыНаСкладах.Остатки КАК ТоварыНаСкладахОстатки
        |ГДЕ
        |    ТоварыНаСкладахОстатки.Склад = &Склад
        |    И ТоварыНаСкладахОстатки.Номенклатура В ИЕРАРХИИ (&ГруппаНоменклатуры)
        |";
        Запрос.УстановитьПараметр("Склад", Склад);
        Запрос.УстановитьПараметр("ГруппаНоменклатуры", ГруппаНоменклатуры);
        РезультатЗапроса = Запрос.Выполнить();
        Выборка = РезультатЗапроса.Выбрать();
        Пока Выборка.Следующий() Цикл
            НоваяСтрока = ТаблицаОстатков.Добавить();
            НоваяСтрока.Номенклатура = Выборка.Номенклатура;
            НоваяСтрока.Остаток = Выборка.Остаток;
        КонецЦикла;
    КонецЕсли;

    Возврат ТаблицаОстатков;

