        СоответствиеЦен.Вставить(Выборка.Номенклатура, Выборка.Цена);
    КонецЦикла;

    Для каждого Строка Из ТабЧасть Цикл
        Цена = 0;
        Если СоответствиеЦен.Получить(Строка.Номенклатура) <> Неопределено Тогда
            Цена = СоответствиеЦен.Получить(Строка.Номенклатура);
        КонецЕсли;
        Строка.Цена = Цена;
        Строка.Сумма = Строка.Количество * Цена;
    КонецЦикла;

