		|	РегистрСведений.ЦеныНоменклатуры.СрезПоследних(
		|		&Период,
		|		ВидЦен = &ВидЦен
		|		И Номенклатура В (&СписокНоменклатуры)
		|	) КАК Цены";

	// Формируем соответствие Номенклатура -> Цена
	ЦеныНоменклатуры = Новый Соответствие;
	Выборка = Запрос.Выполнить().Выбрать();
	Пока Выборка.Следующий() Цикл
		ЦеныНоменклатуры.Вставить(Выборка.Номенклатура, Выборка.Цена);
	КонецЦикла;

	// Заполняем цены и пересчитываем суммы в табличной части
	Для Каждого СтрокаТовары Из Товары Цикл
		Цена = ЦеныНоменклатуры.Получить(СтрокаТовары.Номенклатура);
		Если Цена = Неопределено Тогда
			СтрокаТовары.Цена = 0;
		Иначе
			СтрокаТовары.Цена = Цена;
		КонецЕсли;
		СтрокаТовары.Сумма = СтрокаТовары.Количество * СтрокаТовары.Цена;
	КонецЦикла;

