            МассивНоменклатуры.Добавить(СтрокаТЧ.Номенклатура);
        КонецЕсли;
    КонецЦикла;

    Запрос = Новый Запрос;
    Запрос.Текст =
    "ВЫБРАТЬ
    |   ЦеныНоменклатуры.Номенклатура КАК Номенклатура,
    |   ЦеныНоменклатуры.Цена КАК Цена
    |ИЗ
    |   РегистрСведений.ЦеныНоменклатуры.СрезПоследних(
    |       &Дата,
    |       ВидЦен = &ВидЦен
    |           И Номенклатура В (&МассивНоменклатуры)) КАК ЦеныНоменклатуры";

    Запрос.УстановитьПараметр("Дата", Дата);
    Запрос.УстановитьПараметр("ВидЦен", ВидЦен);
    Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);

    Выборка = Запрос.Выполнить().Выбрать();

    СоответствиеЦен = Новый Соответствие;
    Пока Выборка.Следующий() Цикл
        СоответствиеЦен.Вставить(Выборка.Номенклатура, Выборка.Цена);
    КонецЦикла;

    Для Каждого СтрокаТЧ Из ТЧ Цикл
        Цена = СоответствиеЦен.Получить(СтрокаТЧ.Номенклатура);
        Если Цена = Неопределено Тогда
            СтрокаТЧ.Цена = 0;
            СтрокаТЧ.Сумма = 0;
        Иначе
            СтрокаТЧ.Цена = Цена;
            СтрокаТЧ.Сумма = СтрокаТЧ.Количество * СтрокаТЧ.Цена;
        КонецЕсли;
    КонецЦикла;

