Функция СписатьТоварыFIFO(ТаблицаТоваров, Склад) Экспорт

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура");
	Результат.Колонки.Добавить("Партия");
	Результат.Колонки.Добавить("Количество");
	Результат.Колонки.Добавить("Стоимость");

	Для Каждого СтрокаТовар Из ТаблицаТоваров Цикл
		Номенклатура = СтрокаТовар.Номенклатура;
		ОсталосьСписать = СтрокаТовар.Количество;

		Запрос = Новый Запрос;
		Запрос.Текст =
			"ВЫБРАТЬ
			|	ПартииТоваровНаСкладахОстатки.Партия КАК Партия,
			|	ПартииТоваровНаСкладахОстатки.КоличествоОстаток КАК Доступно,
			|	ПартииТоваровНаСкладахОстатки.СтоимостьОстаток КАК СтоимостьОстаток
			|ИЗ
			|	РегистрНакопления.ПартииТоваровНаСкладах.Остатки(, Склад = &Склад И Номенклатура = &Номенклатура) КАК ПартииТоваровНаСкладахОстатки
			|УПОРЯДОЧИТЬ ПО
			|	ПартииТоваровНаСкладахОстатки.Партия.Дата,
			|	ПартииТоваровНаСкладахОстатки.Партия";

		Запрос.УстановитьПараметр("Склад", Склад);
		Запрос.УстановитьПараметр("Номенклатура", Номенклатура);

		Выборка = Запрос.Выполнить().Выбрать();

		Пока Выборка.Следующий() И ОсталосьСписать > 0 Цикл
			СписываемоеКоличество = Мин(ОсталосьСписать, Выборка.Доступно);

			СтоимостьСписания = 0;
			Если Выборка.Доступно > 0 Тогда
				СтоимостьСписания = Выборка.СтоимостьОстаток * СписываемоеКоличество / Выборка.Доступно;
			КонецЕсли;

			СтрокаРезультат = Результат.Добавить();
			СтрокаРезультат.Номенклатура = Номенклатура;
			СтрокаРезультат.Партия = Выборка.Партия;
			СтрокаРезультат.Количество = СписываемоеКоличество;
			СтрокаРезультат.Стоимость = СтоимостьСписания;

			ОсталосьСписать = ОсталосьСписать - СписываемоеКоличество;
		КонецЦикла;

		Если ОсталосьСписать > 0 Тогда
			ВызватьИсключение "Недостаточно остатков для номенклатуры: " + Номенклатура.Наименование;
		КонецЕсли;
	КонецЦикла;

	Возврат Результат;

