Функция СписатьТоварыПоФИФО(ТаблицаТоваров, Склад) Экспорт

	Результат = Новый ТаблицаЗначений;
	Результат.Колонки.Добавить("Номенклатура");
	Результат.Колонки.Добавить("Партия");
	Результат.Колонки.Добавить("Количество");
	Результат.Колонки.Добавить("Стоимость");

	СписокНоменклатуры = Новый Массив;
	Для Каждого СтрокаТовара Из ТаблицаТоваров Цикл
		СписокНоменклатуры.Добавить(СтрокаТовара.Номенклатура);
	КонецЦикла;

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ
	|	Остатки.Номенклатура КАК Номенклатура,
	|	Остатки.Партия КАК Партия,
	|	Остатки.Партия.Дата КАК ДатаПартии,
	|	Остатки.КоличествоОстаток КАК КоличествоОстаток,
	|	Остатки.СтоимостьОстаток КАК СтоимостьОстаток
	|ИЗ
	|	РегистрНакопления.ПартииТоваровНаСкладах.Остатки(
	|			,
	|			Склад = &Склад
	|				И Номенклатура В (&СписокНоменклатуры)) КАК Остатки
	|
	|УПОРЯДОЧИТЬ ПО
	|	Номенклатура,
	|	ДатаПартии,
	|	Партия";

	Запрос.УстановитьПараметр("Склад", Склад);
	Запрос.УстановитьПараметр("СписокНоменклатуры", СписокНоменклатуры);

	ОстаткиПоПартиям = Запрос.Выполнить().Выгрузить();

	Для Каждого СтрокаТовара Из ТаблицаТоваров Цикл

		КоличествоСписать = СтрокаТовара.Количество;

		СтрокиПартий = ОстаткиПоПартиям.НайтиСтроки(
			Новый Структура("Номенклатура", СтрокаТовара.Номенклатура));

		Для Каждого СтрокаПартии Из СтрокиПартий Цикл

			Если КоличествоСписать <= 0 Тогда
				Прервать;
			КонецЕсли;

			Если СтрокаПартии.КоличествоОстаток <= 0 Тогда
				Продолжить;
			КонецЕсли;

			СписываемоеКоличество = Мин(КоличествоСписать, СтрокаПартии.КоличествоОстаток);

			Если СписываемоеКоличество = СтрокаПартии.КоличествоОстаток Тогда
				СписываемаяСтоимость = СтрокаПартии.СтоимостьОстаток;
			Иначе
				СписываемаяСтоимость = Окр(СтрокаПартии.СтоимостьОстаток
					* СписываемоеКоличество / СтрокаПартии.КоличествоОстаток, 2);
			КонецЕсли;

			НоваяСтрока = Результат.Добавить();
			НоваяСтрока.Номенклатура = СтрокаТовара.Номенклатура;
			НоваяСтрока.Партия = СтрокаПартии.Партия;
			НоваяСтрока.Количество = СписываемоеКоличество;
			НоваяСтрока.Стоимость = СписываемаяСтоимость;

			СтрокаПартии.КоличествоОстаток = СтрокаПартии.КоличествоОстаток - СписываемоеКоличество;
			СтрокаПартии.СтоимостьОстаток = СтрокаПартии.СтоимостьОстаток - СписываемаяСтоимость;

			КоличествоСписать = КоличествоСписать - СписываемоеКоличество;

		КонецЦикла;

		Если КоличествоСписать > 0 Тогда
			ВызватьИсключение СтрШаблон(
				"Недостаточно остатков на складе: номенклатура ""%1"", не хватает %2 шт.",
				СтрокаТовара.Номенклатура.Наименование,
				КоличествоСписать);
		КонецЕсли;

	КонецЦикла;

	Возврат Результат;

