Функция РассчитатьСреднююСебестоимость(МассивНоменклатуры, Склад, ДатаРасчета)

    Запрос = Новый Запрос;
    Запрос.Текст = 
    "ВЫБРАТЬ
    |    СтоимостьТоваровОстатки.Номенклатура КАК Номенклатура,
    |    СтоимостьТоваровОстатки.КоличествоОстаток КАК Количество,
    |    СтоимостьТоваровОстатки.СтоимостьОстаток КАК Стоимость
    |ИЗ
    |    РегистрНакопления.СтоимостьТоваров.Остатки(&ДатаРасчета, Склад = &Склад И Номенклатура В (&МассивНоменклатуры)) КАК СтоимостьТоваровОстатки";

    Запрос.УстановитьПараметр("ДатаРасчета", КонецДня(ДатаРасчета));
    Запрос.УстановитьПараметр("Склад", Склад);
    Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);

    РезультатЗапроса = Запрос.Выполнить();

    ТаблицаРезультат = Новый ТаблицаЗначений;
    ТаблицаРезультат.Колонки.Добавить("Номенклатура");
    ТаблицаРезультат.Колонки.Добавить("СредняяЦена");

    Выборка = РезультатЗапроса.Выбрать();
    Пока Выборка.Следующий() Цикл
        НоваяСтрока = ТаблицаРезультат.Добавить();
        НоваяСтрока.Номенклатура = Выборка.Номенклатура;
        Если Выборка.Количество > 0 Тогда
            НоваяСтрока.СредняяЦена = Выборка.Стоимость / Выборка.Количество;
        Иначе
            НоваяСтрока.СредняяЦена = 0;
        КонецЕсли;
    КонецЦикла;

    Для Каждого Номенклатура Из МассивНоменклатуры Цикл
