Процедура ПересчитатьСуммыПриСменеВалюты(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса)

	Если ИсходнаяВалюта = НоваяВалюта Тогда
		Возврат;
	КонецЕсли;

	ОтборИсх = Новый Структура("Валюта", ИсходнаяВалюта);
	ЗначенияИсх = РегистрыСведений.КурсыВалют.ПолучитьПоследнее(ДатаКурса, ОтборИсх);
	Если Не ЗначениеЗаполнено(ЗначенияИсх.Курс) Тогда
		ВызватьИсключение "Не найден курс для валюты: " + ИсходнаяВалюта.Наименование;
	КонецЕсли;
	КурсИсх = ЗначенияИсх.Курс;
	КратностьИсх = ?(ЗначенияИсх.Кратность = 0, 1, ЗначенияИсх.Кратность);

	ОтборНов = Новый Структура("Валюта", НоваяВалюта);
	ЗначенияНов = РегистрыСведений.КурсыВалют.ПолучитьПоследнее(ДатаКурса, ОтборНов);
	Если Не ЗначениеЗаполнено(ЗначенияНов.Курс) Тогда
		ВызватьИсключение "Не найден курс для валюты: " + НоваяВалюта.Наименование;
	КонецЕсли;
	КурсНов = ЗначенияНов.Курс;
	КратностьНов = ?(ЗначенияНов.Кратность = 0, 1, ЗначенияНов.Кратность);

	Коэффициент = (КурсИсх * КратностьНов) / (КурсНов * КратностьИсх);

	Для Каждого СтрокаТовары Из Товары Цикл
		СтрокаТовары.Цена = СтрокаТовары.Цена * Коэффициент;
		СтрокаТовары.Сумма = СтрокаТовары.Цена * СтрокаТовары.Количество;
	КонецЦикла;

КонецПроцедуры

Процедура ПересчитатьСуммыДокументаПриСменеВалюты(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

	Если ИсходнаяВалюта = НоваяВалюта Тогда
		Возврат;
	КонецЕсли;

	ДанныеКурсаИсходной = ПолучитьКурсВалюты(ИсходнаяВалюта, ДатаКурса);
	ДанныеКурсаНовой    = ПолучитьКурсВалюты(НоваяВалюта, ДатаКурса);

	КроссКурс = (ДанныеКурсаИсходной.Курс * ДанныеКурсаНовой.Кратность)
		/ (ДанныеКурсаНовой.Курс * ДанныеКурсаИсходной.Кратность);

	Для Каждого СтрокаТовары Из Товары Цикл
		СтрокаТовары.Цена  = Окр(СтрокаТовары.Цена * КроссКурс, 2);
		СтрокаТовары.Сумма = Окр(СтрокаТовары.Количество * СтрокаТовары.Цена, 2);
	КонецЦикла;

КонецПроцедуры

Функция ПолучитьКурсВалюты(Валюта, ДатаКурса)

	Отбор = Новый Структура("Валюта", Валюта);
	ЗначенияКурса = РегистрыСведений.КурсыВалют.ПолучитьПоследнее(ДатаКурса, Отбор);

	Если ЗначенияКурса.Курс = Неопределено
		Или ЗначенияКурса.Курс = 0 Тогда
		ВызватьИсключение СтрШаблон(
			"Не задан курс валюты ""%1"" на дату %2.",
			Валюта.Наименование,
			Формат(ДатаКурса, "ДЛФ=D"));
	КонецЕсли;

	Кратность = ЗначенияКурса.Кратность;
	Если Кратность = Неопределено Или Кратность = 0 Тогда
		Кратность = 1;
	КонецЕсли;

	Возврат Новый Структура("Курс, Кратность", ЗначенияКурса.Курс, Кратность);

КонецФункции

Процедура ПересчитатьСуммыПриСменеВалюты(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

    Если ИсходнаяВалюта = НоваяВалюта Тогда
        Возврат;
    КонецЕсли;

    // Получаем курс исходной валюты
    Запрос = Новый Запрос;
    Запрос.Текст =
        "ВЫБРАТЬ ПЕРВЫЕ 1
        |   КурсыВалют.Курс КАК Курс,
        |   КурсыВалют.Кратность КАК Кратность
        |ИЗ
        |   РегистрСведений.КурсыВалют.СрезПоследних(&Дата, Валюта = &Валюта) КАК КурсыВалют";

    Запрос.УстановитьПараметр("Дата", ДатаКурса);
    Запрос.УстановитьПараметр("Валюта", ИсходнаяВалюта);
    РезультатИсходная = Запрос.Выполнить();

    Если РезультатИсходная.Пустой() Тогда
        ВызватьИсключение "Отсутствует курс валюты: " + Строка(ИсходнаяВалюта) + " на дату " + Формат(ДатаКурса, "ДФ=dd.MM.yyyy");
    КонецЕсли;

    ВыборкаИсходная = РезультатИсходная.Выбрать();
    ВыборкаИсходная.Следующий();
    КурсИсходной   = ВыборкаИсходная.Курс;
    КратностьИсходной = ВыборкаИсходная.Кратность;

    // Получаем курс новой валюты
    Запрос.УстановитьПараметр("Валюта", НоваяВалюта);
    РезультатНовая = Запрос.Выполнить();

    Если РезультатНовая.Пустой() Тогда
        ВызватьИсключение "Отсутствует курс валюты: " + Строка(НоваяВалюта) + " на дату " + Формат(ДатаКурса, "ДФ=dd.MM.yyyy");
    КонецЕсли;

    ВыборкаНовая = РезультатНовая.Выбрать();
    ВыборкаНовая.Следующий();
    КурсНовой   = ВыборкаНовая.Курс;
    КратностьНовой = ВыборкаНовая.Кратность;

    // Кросс-курс: (КурсИсх * КратностьНов) / (КурсНов * КратностьИсх)
    КроссКурс = (КурсИсходной * КратностьНовой) / (КурсНовой * КратностьИсходной);

    // Пересчитываем строки табличной части
    Для Каждого Строка Из Товары Цикл
        Строка.Цена  = Окр(Строка.Цена * КроссКурс, 2);
        Строка.Сумма = Окр(Строка.Количество * Строка.Цена, 2);
    КонецЦикла;

КонецПроцедуры

Процедура ПересчитатьСуммыВВалюту(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст =
		"ВЫБРАТЬ
		|	КурсыВалют.Валюта КАК Валюта,
		|	КурсыВалют.Курс КАК Курс,
		|	КурсыВалют.Кратность КАК Кратность
		|ИЗ
		|	РегистрСведений.КурсыВалют.СрезПоследних(&ДатаКурса, Валюта В (&ИсходнаяВалюта, &НоваяВалюта)) КАК КурсыВалют";

	Запрос.УстановитьПараметр("ИсходнаяВалюта", ИсходнаяВалюта);
	Запрос.УстановитьПараметр("НоваяВалюта", НоваяВалюта);
	Запрос.УстановитьПараметр("ДатаКурса", ДатаКурса);

	Результат = Запрос.Выполнить();

	Если Результат.Пустой() Тогда
		ВызватьИсключение "Отсутствует курс валюты """ + СокрЛП(ИсходнаяВалюта.Наименование)
			+ """ на " + Формат(ДатаКурса, "ДЛФ=DD");
	КонецЕсли;

	КурсИсходной = 0;
	КратностьИсходной = 0;
	КурсНовой = 0;
	КратностьНовой = 0;

	Выборка = Результат.Выбрать();
	Пока Выборка.Следующий() Цикл
		Если Выборка.Валюта = ИсходнаяВалюта Тогда
			КурсИсходной = Выборка.Курс;
			КратностьИсходной = Выборка.Кратность;
		ИначеЕсли Выборка.Валюта = НоваяВалюта Тогда
			КурсНовой = Выборка.Курс;
			КратностьНовой = Выборка.Кратность;
		КонецЕсли;
	КонецЦикла;

	Если КурсИсходной = 0 Тогда
		ВызватьИсключение "Отсутствует курс валюты """ + СокрЛП(ИсходнаяВалюта.Наименование)
			+ """ на " + Формат(ДатаКурса, "ДЛФ=DD");
	КонецЕсли;

	Если КурсНовой = 0 Тогда
		ВызватьИсключение "Отсутствует курс валюты """ + СокрЛП(НоваяВалюта.Наименование)
			+ """ на " + Формат(ДатаКурса, "ДЛФ=DD");
	КонецЕсли;

	Коэффициент = (КурсИсходной * КратностьНовой) / (КурсНовой * КратностьИсходной);

	Для Каждого СтрокаТоваров Из Товары Цикл
		СтрокаТоваров.Цена = Окр(СтрокаТоваров.Цена * Коэффициент, 2);
		СтрокаТоваров.Сумма = Окр(СтрокаТоваров.Цена * СтрокаТоваров.Количество, 2);
	КонецЦикла;

КонецПроцедуры

Процедура ПересчитатьСуммыПриСменеВалюты(Товары, ИсходнаяВалюта, НоваяВалюта, ДатаКурса)

	Если ИсходнаяВалюта = НоваяВалюта Тогда
		Возврат;
	КонецЕсли;

	Отбор = Новый Структура("Валюта", ИсходнаяВалюта);
	КурсИсходной = РегистрыСведений.КурсыВалют.ПолучитьПоследнее(ДатаКурса, Отбор);

	Если КурсИсходной.Курс = 0 Тогда
		ВызватьИсключение "Не найден курс валюты: " + ИсходнаяВалюта;
	КонецЕсли;

	Отбор = Новый Структура("Валюта", НоваяВалюта);
	КурсНовой = РегистрыСведений.КурсыВалют.ПолучитьПоследнее(ДатаКурса, Отбор);

	Если КурсНовой.Курс = 0 Тогда
		ВызватьИсключение "Не найден курс валюты: " + НоваяВалюта;
	КонецЕсли;

	КроссКурс = КурсИсходной.Курс * КурсНовой.Кратность
		/ (КурсИсходной.Кратность * КурсНовой.Курс);

	Для Каждого Строка Из Товары Цикл
		Строка.Цена = Строка.Цена * КроссКурс;
		Строка.Сумма = Строка.Цена * Строка.Количество;
	КонецЦикла;

КонецПроцедуры

