Функция ПолучитьОстаткиИОборотыТоваров(ДатаНач, ДатаКон, Склад = Неопределено) Экспорт

    Запрос = Новый Запрос;
    Запрос.Текст = 
    "ВЫБРАТЬ
    |   Остатки.Номенклатура КАК Номенклатура,
    |   Остатки.КоличествоОстаток КАК НачальныйОстаток
    |ИЗ
    |   РегистрНакопления.ДвиженияТоваров.Остатки(
    |       &ДатаНач,
    |       &УсловиеСклада) КАК Остатки
    |;
    |
    |////////////////////////////////////////////////////////////////////////////////
    |ВЫБРАТЬ
    |   Обороты.Номенклатура КАК Номенклатура,
    |   Обороты.КоличествоПриход КАК Приход,
    |   Обороты.КоличествоРасход КАК Расход
    |ИЗ
    |   РегистрНакопления.ДвиженияТоваров.Обороты(
    |       &ДатаНач,
    |       &ДатаКон,
    |       ,
    |       &УсловиеСклада) КАК Обороты";

    Запрос.УстановитьПараметр("ДатаНач", ДатаНач);
    Запрос.УстановитьПараметр("ДатаКон", ДатаКон);

    Если Склад = Неопределено Тогда
        Запрос.Текст = СтрЗаменить(Запрос.Текст, "&УсловиеСклада", "ИСТИНА");
    Иначе
        Запрос.Текст = СтрЗаменить(Запрос.Текст, "&УсловиеСклада", "Склад = &Склад");
        Запрос.УстановитьПараметр("Склад", Склад);
    КонецЕсли;

    МассивРезультатов = Запрос.ВыполнитьПакет();

    ВыборкаОстатки = МассивРезультатов[0].Выбрать();
    ВыборкаОбороты = МассивРезультатов[1].Выбрать();

    ТЗ = Новый ТаблицаЗначений;
    ТЗ.Колонки.Добавить("Номенклатура");
    ТЗ.Колонки.Добавить("НачальныйОстаток");
    ТЗ.Колонки.Добавить("Приход");
    ТЗ.Колонки.Добавить("Расход");
    ТЗ.Колонки.Добавить("КонечныйОстаток");

    СоответствиеСтрок = Новый Соответствие;

    Пока ВыборкаОстатки.Следующий() Цикл
        НоваяСтрока = ТЗ.Добавить();
        НоваяСтрока.Номенклатура = ВыборкаОстатки.Номенклатура;
        НоваяСтрока.НачальныйОстаток = ВыборкаОстатки.НачальныйОстаток;
        НоваяСтрока.Приход = 0;
        НоваяСтрока.Расход = 0;
        НоваяСтрока.КонечныйОстаток = ВыборкаОстатки.НачальныйОстаток;
        СоответствиеСтрок.Вставить(ВыборкаОстатки.Номенклатура, НоваяСтрока);
    КонецЦикла;

    Пока ВыборкаОбороты.Следующий() Цикл
        Строка = СоответствиеСтрок.Получить(ВыборкаОбороты.Номенклатура);
        Если Строка = Неопределено Тогда
            Строка = ТЗ.Добавить();
            Строка.Номенклатура = ВыборкаОбороты.Номенклатура;
            Строка.НачальныйОстаток = 0;
            Строка.КонечныйОстаток = 0;
            СоответствиеСтрок.Вставить(ВыборкаОбороты.Номенклатура, Строка);
        КонецЕсли;
        Строка.Приход = ВыборкаОбороты.Приход;
        Строка.Расход = ВыборкаОбороты.Расход;
        Строка.КонечныйОстаток = Строка.НачальныйОстаток + Строка.Приход - Строка.Расход;
    КонецЦикла;

    Возврат ТЗ;

КонецФункции

