Функция РассчитатьСвободныйОстаток(МассивНоменклатуры, Склад) Экспорт

    Результат = Новый ТаблицаЗначений;
    Результат.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    Результат.Колонки.Добавить("Свободно", Новый ОписаниеТипов("Число", Новый КвалификаторыЧисла(15, 3)));

    Запрос = Новый Запрос;
    Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);
    Запрос.УстановитьПараметр("Склад", Склад);

    Запрос.Текст =
    "ВЫБРАТЬ
    |   ТоварыНаСкладахОстатки.Номенклатура КАК Номенклатура,
    |   ТоварыНаСкладахОстатки.ВНаличииОстаток КАК ВНаличии,
    |   ЕСТЬNULL(РезервыОстатки.ЗарезервированоОстаток, 0) КАК Зарезервировано
    |ИЗ
    |   РегистрНакопления.ТоварыНаСкладах.Остатки(, Склад = &Склад И Номенклатура В (&МассивНоменклатуры)) КАК ТоварыНаСкладахОстатки
    |   ЛЕВОЕ СОЕДИНЕНИЕ РегистрНакопления.Резервы.Остатки(, Склад = &Склад И Номенклатура В (&МассивНоменклатуры)) КАК РезервыОстатки
    |   ПО ТоварыНаСкладахОстатки.Номенклатура = РезервыОстатки.Номенклатура
    |       И ТоварыНаСкладахОстатки.Склад = РезервыОстатки.Склад";

    Выборка = Запрос.Выполнить().Выбрать();

    Пока Выборка.Следующий() Цикл
        НоваяСтрока = Результат.Добавить();
        НоваяСтрока.Номенклатура = Выборка.Номенклатура;
        НоваяСтрока.Свободно = Выборка.ВНаличии - Выборка.Зарезервировано;
    КонецЦикла;

    Возврат Результат;

КонецФункции

Функция РасчетСвободногоОстатка(МассивНоменклатуры, Склад)

    Запрос = Новый Запрос;
    Запрос.Текст = 
    "ВЫБРАТЬ
    |   ТоварыНаСкладахОстатки.Номенклатура КАК Номенклатура,
    |   ТоварыНаСкладахОстатки.ВНаличииОстаток КАК ВНаличии
    |ПОМЕСТИТЬ ВТ_Остатки
    |ИЗ
    |   РегистрНакопления.ТоварыНаСкладах.Остатки(
    |       ,
    |       Склад = &Склад
    |           И Номенклатура В (&МассивНоменклатуры)) КАК ТоварыНаСкладахОстатки
    |;
    |
    |////////////////////////////////////////////////////////////////////////////////
    |ВЫБРАТЬ
    |   РезервыОстатки.Номенклатура КАК Номенклатура,
    |   РезервыОстатки.ЗарезервированоОстаток КАК Зарезервировано
    |ПОМЕСТИТЬ ВТ_Резервы
    |ИЗ
    |   РегистрНакопления.Резервы.Остатки(
    |       ,
    |       Склад = &Склад
    |           И Номенклатура В (&МассивНоменклатуры)) КАК РезервыОстатки
    |;
    |
    |////////////////////////////////////////////////////////////////////////////////
    |ВЫБРАТЬ
    |   ЕСТЬNULL(ВТ_Остатки.Номенклатура, ВТ_Резервы.Номенклатура) КАК Номенклатура,
    |   ЕСТЬNULL(ВТ_Остатки.ВНаличии, 0) - ЕСТЬNULL(ВТ_Резервы.Зарезервировано, 0) КАК Свободно
    |ИЗ
    |   ВТ_Остатки КАК ВТ_Остатки
    |       ПОЛНОЕ СОЕДИНЕНИЕ ВТ_Резервы КАК ВТ_Резервы
    |       ПО ВТ_Остатки.Номенклатура = ВТ_Резервы.Номенклатура";

    Запрос.УстановитьПараметр("Склад", Склад);
    Запрос.УстановитьПараметр("МассивНоменклатуры", МассивНоменклатуры);

    ТаблицаЗначений = Новый ТаблицаЗначений;
    ТаблицаЗначений.Колонки.Добавить("Номенклатура", Новый ОписаниеТипов("СправочникСсылка.Номенклатура"));
    ТаблицаЗначений.Колонки.Добавить("Свободно", Новый ОписаниеТипов("Число", , , Новый КвалификаторыЧисла(15, 3)));

    РезультатЗапроса = Запрос.Выполнить();
    Если НЕ РезультатЗапроса.Пустой() Тогда
        Выборка = РезультатЗапроса.Выбрать();
        Пока Выборка.Следующий() Цикл
            НоваяСтрока = ТаблицаЗначений.Добавить();
            НоваяСтрока.Номенклатура = Выборка.Номенклатура;
            НоваяСтрока.Свободно = Выборка.Свободно;
        КонецЦикла;
    КонецЕсли;

    Возврат ТаблицаЗначений;

КонецФункции

Функция ABCКлассификация(НачалоПериода, КонецПериода) Экспорт

