    СтавкаНДС = Константы.СтавкаНДС.Получить();

    // Переводим ставку из процентов в доли единицы
    СтавкаНДС = СтавкаНДС / 100;

    // Вычисляем сумму НДС
    // Формула: СуммаСНДС - (СуммаСНДС / (1 + СтавкаНДС))
    СуммаНДС = СуммаСНДС - (СуммаСНДС / (1 + СтавкаНДС));

    Возврат СуммаНДС;

